section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/fco-waste-elimination.json",
  "title": "Cloud Waste Elimination and Non-Production Scheduling",
  "type": "object",
  "required": [
    "scope",
    "idle_audit",
    "schedules",
    "exceptions_policy",
    "automation",
    "kpi_targets",
    "owner",
    "last_reviewed"
  ],
  "properties": {
    "scope": {
      "type": "object",
      "required": [
        "accounts",
        "regions",
        "environments"
      ]
    },
    "idle_audit": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": [
          "resource_type",
          "detector",
          "action"
        ]
      }
    },
    "schedules": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": [
          "env",
          "begin",
          "end",
          "weekdays",
          "timezone"
        ]
      }
    },
    "exceptions_policy": {
      "type": "object",
      "required": [
        "tag_key",
        "required_fields",
        "expiry_days"
      ]
    },
    "automation": {
      "type": "object",
      "required": [
        "scanner",
        "frequency",
        "dry_run_default",
        "notification_channel"
      ]
    },
    "kpi_targets": {
      "type": "object",
      "required": [
        "waste_rate_max_pct",
        "untagged_max_pct",
        "non_prod_savings_min_pct"
      ]
    },
    "owner": {
      "type": "string"
    },
    "last_reviewed": {
      "type": "string"
    }
  },
  "additionalProperties": false
}
